'use strict';

var valid = [];

// Non-require variable declarations (not validated):
var test = {
	'code': [
		'\'use strict\';',
		'',
		'// VARIABLES //',
		'',
		'var x = 1;',
		'',
		'var y = 2;'
	].join( '\n' )
};
valid.push( test );

// Dynamic require (variable path: not a simple require pattern):
test = {
	'code': [
		'\'use strict\';',
		'',
		'var path = \'./foo\';',
		'',
		'var foo = require( path );'
	].join( '\n' )
};
valid.push( test );

// Require without assignment (expression statement, not variable declaration):
test = {
	'code': [
		'\'use strict\';',
		'',
		'require( \'./setup\' );',
		'',
		'require( \'./teardown\' );'
	].join( '\n' )
};
valid.push( test );

// Require in conditional (not module-level):
test = {
	'code': [
		'\'use strict\';',
		'',
		'if ( condition ) {',
		'    var foo = require( \'foo\' );',
		'',
		'    var bar = require( \'bar\' );',
		'}'
	].join( '\n' )
};
valid.push( test );

// Empty file:
test = {
	'code': ''
};
valid.push( test );

// File with only use strict:
test = {
	'code': '\'use strict\';'
};
valid.push( test );


// EXPORTS //

module.exports = valid;
